    let left: Field = 100;
    let right: Field = 200;

    // Direct permutation with H2M layout
    let state: [Field; 4] = [left, right, 0x48324d, 0];
    let out = poseidon2_permutation(state, 4);

    // Must match the circuit's poseidon2_hash2 function
